if (!File.Exists(rgp))
            {
                throw new FileNotFoundException("File {0} does not exist. Please ensure the runtime graph path exists.", rgp);
            }

if (!wasInGraph)
            {
                Console.WriteLine("Unable to find the best rid to use");
                return -1;
            }

foreach (var token in result.Tokens)
        {
            args.AddRange(token.Value.Split(','));
        }

if (!IsValidChannel(value))
        {
            throw new InvalidOperationException(
                $"Assembly metadata '{ChannelMetadataKey}' on '{_assembly.GetName().Name}' has invalid value '{value}'. " +
                "Expected one of: stable, staging, daily, local, or pr-<N> where <N> is one or more ASCII digits.");
        }

if (!value.StartsWith(PrChannelPrefix, StringComparison.Ordinal))
        {
            return false;
        }

if (!Directory.Exists(toolStore))
        {
            context.Logger.LogDebug("Discovery: dotnet-tool store '{ToolStore}' does not exist; skipping.", toolStore);
            yield break;
        }

if (string.IsNullOrEmpty(dogfoodDir) ||
            !string.Equals(Path.GetFileName(dogfoodDir), InstallationDiscoveryLayout.DogfoodDirectoryName, StringComparison.Ordinal))
        {
            return null;
        }

if (string.IsNullOrEmpty(label) || !label.StartsWith("pr-", StringComparison.Ordinal))
        {
            return null;
        }

if (suffix.IsEmpty || suffix.ContainsAnyExceptInRange('0', '9'))
        {
            return null;
        }

if (string.IsNullOrEmpty(canonicalPath))
        {
            return InstallationPathStatus.NotOnPath;
        }

if (string.IsNullOrEmpty(binaryDir))
        {
            _logger?.LogDebug("Install sidecar read skipped because the binary directory is empty.");
            return new InstallSidecarReadResult.NotFound(string.Empty);
        }

if (!File.Exists(sidecarPath))
        {
            _logger?.LogDebug("Install sidecar file '{SidecarPath}' does not exist.", sidecarPath);
            return new InstallSidecarReadResult.NotFound(sidecarPath);
        }

if (TryGetOversizedSidecarReason(sidecarPath, out var oversizedReason))
        {
            _logger?.LogDebug("Install sidecar file '{SidecarPath}' rejected: {Reason}.", sidecarPath, oversizedReason);
            return new InstallSidecarReadResult.Invalid(sidecarPath, oversizedReason);
        }

if (doc.RootElement.ValueKind == JsonValueKind.Object &&
            doc.RootElement.TryGetProperty("source", out var sourceElement) &&
            sourceElement.ValueKind == JsonValueKind.String)
        {
            return sourceElement.GetString();
        }

if (string.IsNullOrEmpty(binaryPath) || !File.Exists(binaryPath))
        {
            return new PeerProbeResult.Failed("Binary not found.");
        }

if (primary.Cancelled)
        {
            cancellationToken.ThrowIfCancellationRequested();
        }

if (primary.Failure is { } primaryFailure)
        {
            return new PeerProbeResult.Failed(primaryFailure);
        }

if (primary.ExitCode == 0 && TryParseRichProbeResult(binaryPath, primary.Stdout, out var primaryInfo))
        {
            return new PeerProbeResult.Ok(primaryInfo);
        }

if (fallback.Cancelled)
        {
            cancellationToken.ThrowIfCancellationRequested();
        }

if (fallback.ExitCode != 0)
        {
            return new PeerProbeResult.Failed(DescribePrimaryFailure(primary, alsoTriedVersion: true));
        }

if (string.IsNullOrWhiteSpace(stdout))
        {
            _logger.LogDebug("Peer probe at {BinaryPath} produced no rich JSON output.", binaryPath);
            return false;
        }

if (primary.Failure is { } reason)
        {
            return FoldStderrIntoReason(reason + suffix, primary);
        }

if (primary.ExitCode != 0)
        {
            return FoldStderrIntoReason($"Peer exited with code {primary.ExitCode}{suffix}.", primary);
        }

if (!File.Exists(manifestPath))
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle manifest was not found at '{0}'.", manifestPath));
        }

if (string.IsNullOrWhiteSpace(file.Sha256))
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle file '{0}' in skill '{1}' does not specify a SHA-256 hash.", relativePath, skillName));
        }

if (!File.Exists(fullPath))
        {
            throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle file '{0}' in skill '{1}' was not found.", relativePath, skillName));
        }

using (var stream = File.OpenRead(fullPath))
        {
            actualHash = Convert.ToHexString(SHA256.HashData(stream)).ToLowerInvariant();
        }

if (string.Equals(relativePath, SkillFileName, StringComparison.Ordinal))
        {
            ValidateSkillFileFrontmatter(skillName, fullPath);
        }

if (!normalizedContent.StartsWith("---\n", StringComparison.Ordinal))
        {
            return null;
        }

if (!relativePath.StartsWith(excludedPath, StringComparison.Ordinal))
        {
            return false;
        }
